CREATE TABLE users_simple (id INT, name VARCHAR(100));
CREATE TABLE orders_simple (id INT, user_id INT, amount INT);
-- Ніхто не заборонить вам записати сюди user_id = 99999, якого не існує.

SELECT users.name, orders.amount
FROM users
INNER JOIN orders ON users.id = orders.user_id;

SELECT users.name, orders.amount
FROM users
LEFT JOIN orders ON users.id = orders.user_id;

SELECT name FROM users
LEFT JOIN orders ON users.id = orders.user_id
WHERE orders.id IS NULL;

CREATE TABLE products (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255),
    price DECIMAL(10, 2),
    details JSON -- Ось наша магічна колонка
);

-- Показати назву товару і його колір (якщо є)
SELECT name, details->>'$.color' as color
FROM products;

UPDATE products
SET details = JSON_SET(details, '$.ram', '64GB')
WHERE name = 'MacBook Pro';

UPDATE products
SET details = JSON_REMOVE(details, '$.material')
WHERE name = 'Nike T-Shirt';

-- 1. Створюємо віртуальну колонку для кольору
ALTER TABLE products
ADD COLUMN color VARCHAR(50)
GENERATED ALWAYS AS (details->>'$.color') STORED;

-- 2. Створюємо індекс на цю колонку
CREATE INDEX idx_color ON products(color);
